/* ── Input Validation (Red Underline on Blur) ── */
const validateInputs = [fDate, fTime, cityInput];
validateInputs.forEach(input => {
  if (input) {
    // When user leaves the field
    input.addEventListener('blur', () => {
      if (!input.value.trim()) input.classList.add('invalid-input');
      else input.classList.remove('invalid-input');
    });
    // Remove the red line as soon as they start typing/selecting
    input.addEventListener('input', () => {
      if (input.value.trim()) input.classList.remove('invalid-input');
    });
  }
});
/* ── City autocomplete ── */
let debounceTimer = null;

cityInput.addEventListener('input', () => {
  clearTimeout(debounceTimer);
  cityInput.classList.remove('city-selected');
  fLat.value = '';
  fLon.value = '';
  locStatus.hidden = false;
  const val = cityInput.value.trim();
  if (val.length < 1) { hideSuggestions(); return; }
  debounceTimer = setTimeout(() => fetchCities(val), 250);
});

async function fetchCities(q) {
  try {
    const url = `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(q)}&format=json&limit=6&addressdetails=1`;
    const r = await fetch(url, { headers: { 'Accept-Language': 'en' } });
    const raw = await r.json();
    const data = raw.map(item => {
      const addr = item.address || {};
      const city = addr.city || addr.town || addr.village || addr.municipality || item.name;
      return {
        displayName: item.display_name,
        shortName: [city, addr.country].filter(Boolean).join(', '),
        lat: parseFloat(item.lat),
        lon: parseFloat(item.lon)
      };
    });
    showSuggestions(data);
  } catch {
    hideSuggestions();
  }
}

function showSuggestions(items) {
  cityDropdown.innerHTML = '';
  if (!items.length) { cityDropdown.hidden = true; return; }
  items.forEach(item => {
    const li = document.createElement('li');
    li.setAttribute('role', 'option');

    const primary = document.createElement('span');
    primary.className = 'sug-primary';
    primary.textContent = item.shortName;

    const secondary = document.createElement('span');
    secondary.className = 'sug-secondary';
    secondary.textContent = item.displayName;

    li.appendChild(primary);
    li.appendChild(secondary);
    li.addEventListener('mousedown', e => {
      e.preventDefault();
      selectCity(item);
    });
    cityDropdown.appendChild(li);
  });
  cityDropdown.hidden = false;
}

function hideSuggestions() {
  cityDropdown.hidden = true;
  cityDropdown.innerHTML = '';
}
async function selectCity(item) {
  cityInput.value = item.shortName;
  fLat.value = item.lat;
  fLon.value = item.lon;
  hideSuggestions();
  locStatus.hidden = true;
  cityInput.classList.add('city-selected');
  await fetchTimezone(item.lat, item.lon);

  // Trigger preview update if date and time are already set
  if (fDate.value && fTime.value) {
    const [y, mo, d] = fDate.value.split('-').map(Number);
    if (y && mo && d) tryLiveAsc(y, mo, d);
  }
}

document.addEventListener('click', e => {
  if (!e.target.closest('.sentence-city')) hideSuggestions();
});

/* ── Historical UTC offset using Intl (accounts for DST in the birth year) ── */
function getHistoricalUtcOffset(y, mo, d, localH, tzName) {
  if (!tzName) return null;
  try {
    const approxUtc = new Date(Date.UTC(y, mo - 1, d, Math.floor(localH), Math.round((localH % 1) * 60)));
    const parts = new Intl.DateTimeFormat('en', {
      timeZone: tzName, timeZoneName: 'shortOffset', hour12: false
    }).formatToParts(approxUtc);
    const tzStr = parts.find(p => p.type === 'timeZoneName')?.value || '';
    const m = tzStr.match(/GMT([+-])(\d+)(?::(\d+))?/);
    if (!m) return null;
    return (m[1] === '+' ? 1 : -1) * (parseInt(m[2]) + parseInt(m[3] || '0') / 60);
  } catch { return null; }
}

/* ── Timezone detection ── */
async function fetchTimezone(lat, lon) {
  if (locStatus) { locStatus.hidden = false; locStatus.textContent = 'Detecting timezone…'; }
  try {
    const r = await fetch(`/api/timezone?lat=${lat}&lon=${lon}`);
    const data = await r.json();
    if (data.utcOffset != null && fUtc) fUtc.value = data.utcOffset;
    if (data.timeZone && fTz) {
      fTz.value = data.timeZone;
      if (locStatus) {
        const sign = data.utcOffset >= 0 ? '+' : '';
        locStatus.textContent = `${data.timeZone} (UTC${sign}${data.utcOffset})`;
      }
    } else if (locStatus) {
      locStatus.textContent = 'Timezone detected';
    }
  } catch {
    console.warn("Timezone fetch failed");
    if (locStatus) locStatus.textContent = 'Timezone auto-detect unavailable — check UTC offset';
  }
}

/* ── Form validation & submit ── */
calcForm.addEventListener('submit', async e => {
  e.preventDefault();
  if (formError) formError.textContent = '';

  const missing = [];
  
  if (!fDate.value) missing.push('date');
  else if (fDate.value.split('-')[0].length > 4) {
    if (formError) formError.textContent = 'Please enter a valid 4-digit year.';
    fDate.classList.add('invalid-input');
    return;
  }
  if (!fTime.value) missing.push('time');
  
  // Custom check for the City Dropdown
  if (!fLat.value) {
    if (cityInput.value.trim().length > 0) {
      // They typed something but didn't select from the list
      if (formError) {
        formError.textContent = "Almost there! Please select your exact city from the dropdown list so we can find your coordinates.";
      }
      cityInput.classList.add('invalid-input');
      return; // Stop the form submission immediately
    } else {
      // They left it completely blank
      missing.push('birth city');
    }
  }

  if (missing.length) {
    if (formError) formError.textContent = `Please fill in: ${missing.join(', ')}.`;
    return;
  }

  btnSubmit.classList.add('loading');
  btnSubmit.disabled = true;

  try {
    const [yearStr, monthStr, dayStr] = fDate.value.split('-');
    const [hStr, mStr] = fTime.value.split(':');
    const y   = parseInt(yearStr, 10);
    const mo  = parseInt(monthStr, 10);
    const d   = parseInt(dayStr, 10);
    const lat = parseFloat(fLat.value);
    const lon = parseFloat(fLon.value);
    const localH = parseInt(hStr, 10) + parseInt(mStr, 10) / 60;
    const tzName = fTz?.value || '';
    const historicalUtc = getHistoricalUtcOffset(y, mo, d, localH, tzName);
    const utc = historicalUtc ?? (fUtc && fUtc.value ? parseFloat(fUtc.value) : 0);
    let hUT   = localH - utc;

    // Roll day boundaries
    let yd = d, ym = mo, yy = y;
    while (hUT < 0)  { hUT += 24; yd--; if (yd < 1) { ym--; if (ym < 1) { ym = 12; yy--; } yd = new Date(yy, ym, 0).getDate(); } }
    while (hUT >= 24){ hUT -= 24; yd++; const last = new Date(yy, ym, 0).getDate(); if (yd > last) { yd = 1; ym++; if (ym > 12) { ym = 1; yy++; } } }

    const data = buildFullResult(yy, ym, yd, hUT, lat, lon);
    showResult(data);
    captureEmail(fEmail?.value?.trim());
  } catch (err) {
    if (formError) formError.textContent = err.message || 'Calculation failed.';
  } finally {
    btnSubmit.classList.remove('loading');
    btnSubmit.disabled = false;
  }
});

