/* ── Progressive wheel reveal ── */
let progressiveTimer = null;

function showWheelPreview(planets, cusps, animate = false, ascLon = null, mcLon = null) {
  if (mainGrid) mainGrid.classList.add('has-results');
  wheelPanel.hidden = false;
  if (signIntro) signIntro.hidden = true;
  renderWheel(ascLon, mcLon, planets, cusps, animate);
}

fDate.addEventListener('input', () => {
  const v = fDate.value;
  if (!v) return;
  const parts = v.split('-');
  if (parts[0].length > 4) {
    parts[0] = parts[0].slice(0, 4);
    fDate.value = parts.join('-');
    return;
  }
  fDate.classList.remove('invalid-input');
  const [yStr] = parts;
  const y = Number(yStr);
  if (!y || y < 1800 || y > 2200) return;

  clearTimeout(progressiveTimer);

  // Stage 1: outer planets for Jan 1 of this year
  const jdOuter = julianDay(y, 1, 1, 12);
  const outerPlanets = calcPlanets(jdOuter, OUTER_KEYS);
  showWheelPreview(outerPlanets, NEUTRAL_CUSPS, true);

  if (!mo || !d) return;

  // Stage 2: all planets at noon on the actual date
  progressiveTimer = setTimeout(() => {
    const jdFull = julianDay(y, mo, d, 12);
    const allNoon = calcPlanets(jdFull);
    showWheelPreview(allNoon, NEUTRAL_CUSPS, true);

    // Stage 3: if time + location already set, orient to real ASC immediately
    if (fTime.value && fLat.value) {
      tryLiveAsc(y, mo, d);
    }
  }, 450);
});

fTime.addEventListener('input', () => {
  if (!fDate.value || !fLat.value) return;
  const [y, mo, d] = fDate.value.split('-').map(Number);
  if (!y || !mo || !d) return;
  clearTimeout(progressiveTimer);
  progressiveTimer = setTimeout(() => tryLiveAsc(y, mo, d), 350);
});

function tryLiveAsc(y, mo, d) {
  if (!fTime.value || !fLat.value) return;
  const [hStr, mStr] = fTime.value.split(':');
  const localH = parseInt(hStr, 10) + parseInt(mStr, 10) / 60;
  const tzName = fTz?.value || '';
  const historicalUtc = getHistoricalUtcOffset(y, mo, d, localH, tzName);
  const utc = historicalUtc ?? (fUtc?.value ? parseFloat(fUtc.value) : 0);
  let hUT = localH - utc;
  const lat = parseFloat(fLat.value);
  const lon = parseFloat(fLon.value);

  let yd = d, ym = mo, yy = y;
  while (hUT < 0)  { hUT += 24; yd--; if (yd < 1) { ym--; if (ym < 1) { ym = 12; yy--; } yd = new Date(yy, ym, 0).getDate(); } }
  while (hUT >= 24){ hUT -= 24; yd++; const last = new Date(yy, ym, 0).getDate(); if (yd > last) { yd = 1; ym++; if (ym > 12) { ym = 1; yy++; } } }

  try {
    const jd     = julianDay(yy, ym, yd, hUT);
    const ascLon = calcAscendant(jd, lat, lon);
    const mcLon  = calcMC(jd, lon);
    const cusps  = wholeSignCusps(ascLon);
    const planets = calcPlanets(jd);
    showWheelPreview(planets, cusps, true, ascLon, mcLon);
  } catch {}
}

/* ── Display result ── */
function showResult({ ascendant, midheaven, houseSystem, planets, cusps }) {
  // 1. Render Wheel (final, oriented with ASC marker)
  renderWheel(ascendant.longitude, midheaven?.longitude ?? null, planets || {}, cusps || [], true);

  // Helper to map a sign to its CSS elemental color class
  const getElementClass = (signName) => {
    const el = SIGN_META[signName]?.element;
    if (el === 'Fire') return 'color-fire';
    if (el === 'Earth') return 'color-earth';
    if (el === 'Air') return 'color-air';
    if (el === 'Water') return 'color-water';
    return '';
  };

  // 2. Custom Base64 Icons (Replacing text emojis)
  const CUSTOM_ICONS = {
    ascendant: `<img src="data:image/svg+xml;base64," class="custom-glyph" alt="Ascendant icon">`,
    sun: `<img src="data:image/svg+xml;base64," class="custom-glyph" alt="Sun icon">`,
    moon: `<img src="data:image/svg+xml;base64," class="custom-glyph" alt="Moon icon">`,
    mercury: `<img src="data:image/svg+xml;base64," class="custom-glyph" alt="Mercury icon">`,
    venus: `<img src="data:image/svg+xml;base64," class="custom-glyph" alt="Venus icon">`,
    mars: `<img src="data:image/svg+xml;base64," class="custom-glyph" alt="Mars icon">`,
    jupiter: `<img src="data:image/svg+xml;base64," class="custom-glyph" alt="Jupiter icon">`,
    saturn: `<img src="data:image/svg+xml;base64," class="custom-glyph" alt="Saturn icon">`,
    uranus: `<img src="data:image/svg+xml;base64," class="custom-glyph" alt="Uranus icon">`,
    neptune: `<img src="data:image/svg+xml;base64," class="custom-glyph" alt="Neptune icon">`,
    pluto: `<img src="data:image/svg+xml;base64," class="custom-glyph" alt="Pluto icon">`
  };

  // 3. Render birth details header
  const birthDetailsEl = document.getElementById('birth-details');
  if (birthDetailsEl) {
    const [yr, mo2, dy] = fDate.value.split('-');
    const dateObj = new Date(Number(yr), Number(mo2) - 1, Number(dy));
    const dow     = dateObj.toLocaleDateString('en-US', { weekday: 'short' }).toUpperCase();
    const month   = dateObj.toLocaleDateString('en-US', { month:   'short' }).toUpperCase();
    const dayNum  = String(Number(dy));
    const [hh, mm] = fTime.value.split(':');
    const h = Number(hh), ampm = h >= 12 ? 'PM' : 'AM';
    const timePart = `${h % 12 || 12}:${mm}`;
    const city = cityInput.value;
    birthDetailsEl.innerHTML = `
      <div class="bdb-top">
        <span class="bdb-meta bdb-top-align">${dow}</span>
        <span class="bdb-day">${dayNum}</span>
        <span class="bdb-month-year">
          <span class="bdb-meta">${month}</span>
          <span class="bdb-meta">${yr}</span>
        </span>
        <span class="bdb-time">${timePart}</span>
        <span class="bdb-meta bdb-top-align">${ampm}</span>
      </div>
      ${city ? `<div class="bdb-city">${city}</div>` : ''}
    `;
  }

  // 4. Render Big Three Summary Sentence
  const summaryEl = document.getElementById('big-three-summary');
  if (summaryEl && ascendant && planets.sun && planets.moon) {
    const ascClass = getElementClass(ascendant.sign);
    const sunClass = getElementClass(planets.sun.sign);
    const moonClass = getElementClass(planets.moon.sign);

    summaryEl.innerHTML = `Ascendant ${CUSTOM_ICONS.ascendant} in <strong class="${ascClass}">${ascendant.sign.toUpperCase()}</strong>. 
    <br> Sun ${CUSTOM_ICONS.sun} in <strong class="${sunClass}">${planets.sun.sign.toUpperCase()}</strong>. 
    <br> Moon ${CUSTOM_ICONS.moon} in <strong class="${moonClass}">${planets.moon.sign.toUpperCase()}</strong>.`;
  }

  // 4. Render Placement List
  const listEl = document.getElementById('placement-list');
  if (listEl) {
    listEl.innerHTML = ''; // Clear previous results

    const createRow = (signName, bodyKey, degreeObj) => {
      const li = document.createElement('li');
      li.className = 'placement-item';
      
      const signDisplay = signName.toUpperCase();
      const degStr = `${degreeObj.degree}°${String(degreeObj.minute).padStart(2, '0')}'`;
      const elClass = getElementClass(signName);
      
      // Look up the matching SVG (or fallback to empty string)
      const iconHtml = CUSTOM_ICONS[bodyKey] || '';
      
      // Capitalize planet names correctly
      const NAME_OVERRIDES = { ascendant: 'Ascendant', descendant: 'Descendant', midheaven: 'Midheaven', ic: 'Imum Coeli' };
      const formattedName = NAME_OVERRIDES[bodyKey] || (bodyKey.charAt(0).toUpperCase() + bodyKey.slice(1));

      li.innerHTML = `
        <span class="pi-sign ${elClass}">${signDisplay}</span>
        <span class="pi-planet">${iconHtml} ${formattedName}</span>
        <span class="pi-degree">${degStr}</span>
      `;
      listEl.appendChild(li);
    };

    // --- Render "The Big Three" First ---
    if (ascendant) createRow(ascendant.sign, 'ascendant', ascendant);
    if (ascendant) { const dsc = makeLonInfo(ascendant.longitude + 180); createRow(dsc.sign, 'descendant', dsc); }
    if (planets.sun) createRow(planets.sun.sign, 'sun', planets.sun);
    if (planets.moon) createRow(planets.moon.sign, 'moon', planets.moon);

    // --- Render the rest of the planets ---
    const restOrder = ['mercury', 'venus', 'mars', 'jupiter', 'saturn', 'uranus', 'neptune', 'pluto'];
    restOrder.forEach(key => {
      if (planets[key]) {
        createRow(planets[key].sign, key, planets[key]);
      }
    });

    // Render Midheaven and IC
    if (midheaven) createRow(midheaven.sign, 'midheaven', midheaven);
    if (midheaven) { const ic = makeLonInfo(midheaven.longitude + 180); createRow(ic.sign, 'ic', ic); }
  }

  // 5. Switch views
  formPanel.hidden  = true;
  analysisCol.hidden = false;
  wheelPanel.hidden  = false;
  if (mainGrid) mainGrid.classList.add('has-results');
  if (signIntro) signIntro.hidden = true;
}

function formatDegree({ degree, minute, sign }) {
  return `${degree}° ${String(minute).padStart(2, '0')}′ ${sign}`;
}

/* ── Recalculate ── */
btnRecalc.addEventListener('click', () => {
  analysisCol.hidden = true;
  formPanel.hidden   = false;
  wheelPanel.hidden  = true;
  if (mainGrid) mainGrid.classList.remove('has-results');
  formPanel.scrollIntoView({ behavior: 'smooth', block: 'start' });
});

/* ── Zodiac wheel (Canvas) ── */
const W_SIGN_PATHS = [
  ["M12 5a5 5 0 1 0 -4 8","M16 13a5 5 0 1 0 -4 -8","M12 21l0 -16"],
  ["M6 3a6 6 0 0 0 12 0","M6 15a6 6 0 1 0 12 0a6 6 0 1 0 -12 0"],
  ["M3 3a21 21 0 0 0 18 0","M3 21a21 21 0 0 1 18 0","M7 4.5l0 15","M17 4.5l0 15"],
  ["M3 12a3 3 0 1 0 6 0a3 3 0 1 0 -6 0","M15 12a3 3 0 1 0 6 0a3 3 0 1 0 -6 0","M3 12a10 6.5 0 0 1 14 -6.5","M21 12a10 6.5 0 0 1 -14 6.5"],
  ["M13 17a4 4 0 1 0 8 0","M3 16a3 3 0 1 0 6 0a3 3 0 1 0 -6 0","M7 7a4 4 0 1 0 8 0a4 4 0 1 0 -8 0","M7 7c0 3 2 5 2 9","M15 7c0 4 -2 6 -2 10"],
  ["M3 4a2 2 0 0 1 2 2v9","M5 6a2 2 0 0 1 4 0v9","M9 6a2 2 0 0 1 4 0v10a7 5 0 0 0 7 5","M12 21a7 5 0 0 0 7 -5v-2a3 3 0 0 0 -6 0"],
  ["M5 20l14 0","M5 17h5v-.3a7 7 0 1 1 4 0v.3h5"],
  ["M3 4a2 2 0 0 1 2 2v9","M5 6a2 2 0 0 1 4 0v9","M9 6a2 2 0 0 1 4 0v10a3 3 0 0 0 3 3h5","M18 22l3 -3m-3 3l3 3"],
  ["M4 20l16 -16","M13 4h7v7","M6.5 12.5l5 5"],
  ["M4 4a3 3 0 0 1 3 3v9","M7 7a3 3 0 0 1 6 0v11a3 3 0 0 1 -3 3","M16 17a3 3 0 1 0 0.001 0"],
  ["M3 10l3 -3l3 3l3 -3l3 3l3 -3l3 3","M3 17l3 -3l3 3l3 -3l3 3l3 -3l3 3"],
  ["M5 3a21 21 0 0 1 0 18","M19 3a21 21 0 0 0 0 18","M5 12l14 0"],
];
const W_ELEM_COLOR = {
  fire:[235,65,40], earth:[45,175,70], air:[120,80,228], water:[45,118,222]
};
const W_ELEM_LIGHT = {
  fire:[242,80,52], earth:[58,188,82], air:[132,92,238], water:[58,128,232]
};
const W_PLANET_COLOR = {
  sun:[240,185,70], moon:[190,210,240], mercury:[130,190,140], venus:[215,140,165],
  mars:[200,80,65], jupiter:[215,150,80], saturn:[175,155,100],
  uranus:[100,195,210], neptune:[85,120,195], pluto:[160,100,175],
};
const W_ELEMENTS = ['fire','earth','air','water','fire','earth','air','water','fire','earth','air','water'];

const W_ASPECTS = [
  { deg:0,   orb:8,  rgb:[160,160,160], label:'conjunction'  },
  { deg:60,  orb:5,  rgb:[100,180,130], label:'sextile'      },
  { deg:90,  orb:7,  rgb:[180,80,80],   label:'square'       },
  { deg:120, orb:7,  rgb:[80,140,210],  label:'trine'        },
  { deg:180, orb:8,  rgb:[140,80,180],  label:'opposition'   },
];

function _parseSvgPath(d) {
  const cmds = [];
  const re = /([MmLlCcQqAaHhVvZzSsTt])([^MmLlCcQqAaHhVvZzSsTt]*)/g;
  let m;
  while ((m = re.exec(d)) !== null) {
    const cmd = m[1];
    const nums = (m[2].match(/-?[\d.]+(?:e[+-]?\d+)?/gi) || []).map(Number);
    cmds.push({ cmd, nums });
  }
  return cmds;
}

function _tracePathCmds(ctx, cmds, sx, sy) {
  let cx = 0, cy = 0;
  for (const { cmd, nums } of cmds) {
    switch (cmd) {
      case 'M': ctx.moveTo(nums[0]*sx, nums[1]*sy); cx=nums[0]; cy=nums[1]; break;
      case 'm': ctx.moveTo((cx+nums[0])*sx, (cy+nums[1])*sy); cx+=nums[0]; cy+=nums[1]; break;
      case 'L': ctx.lineTo(nums[0]*sx, nums[1]*sy); cx=nums[0]; cy=nums[1]; break;
      case 'l': for(let i=0;i<nums.length;i+=2){cx+=nums[i];cy+=nums[i+1];ctx.lineTo(cx*sx,cy*sy);} break;
      case 'H': ctx.lineTo(nums[0]*sx, cy*sy); cx=nums[0]; break;
      case 'h': cx+=nums[0]; ctx.lineTo(cx*sx, cy*sy); break;
      case 'V': ctx.lineTo(cx*sx, nums[0]*sy); cy=nums[0]; break;
      case 'v': cy+=nums[0]; ctx.lineTo(cx*sx, cy*sy); break;
      case 'C': for(let i=0;i<nums.length;i+=6){ctx.bezierCurveTo(nums[i]*sx,nums[i+1]*sy,nums[i+2]*sx,nums[i+3]*sy,nums[i+4]*sx,nums[i+5]*sy);cx=nums[i+4];cy=nums[i+5];} break;
      case 'c': for(let i=0;i<nums.length;i+=6){ctx.bezierCurveTo((cx+nums[i])*sx,(cy+nums[i+1])*sy,(cx+nums[i+2])*sx,(cy+nums[i+3])*sy,(cx+nums[i+4])*sx,(cy+nums[i+5])*sy);cx+=nums[i+4];cy+=nums[i+5];} break;
      case 'Q': ctx.quadraticCurveTo(nums[0]*sx,nums[1]*sy,nums[2]*sx,nums[3]*sy); cx=nums[2];cy=nums[3]; break;
      case 'q': ctx.quadraticCurveTo((cx+nums[0])*sx,(cy+nums[1])*sy,(cx+nums[2])*sx,(cy+nums[3])*sy); cx+=nums[2];cy+=nums[3]; break;
      case 'A': case 'a': {
        const rel = cmd==='a';
        for (let i=0;i<nums.length;i+=7) {
          const rx=nums[i]*sx, ry=nums[i+1]*sy, xRot=nums[i+2]*Math.PI/180;
          const largeArc=!!nums[i+3], sweep=!!nums[i+4];
          const ex=rel?cx+nums[i+5]:nums[i+5], ey=rel?cy+nums[i+6]:nums[i+6];
          _arcTo(ctx, cx*sx, cy*sy, ex*sx, ey*sy, rx, ry, xRot, largeArc, sweep);
          cx=ex; cy=ey;
        }
        break;
      }
      case 'Z': case 'z': ctx.closePath(); break;
    }
  }
}

function _arcTo(ctx, x1, y1, x2, y2, rx, ry, xRot, largeArc, sweep) {
  const cos = Math.cos(xRot), sin = Math.sin(xRot);
  const dx = (x1-x2)/2, dy = (y1-y2)/2;
  const px = cos*dx + sin*dy, py = -sin*dx + cos*dy;
  let sq = Math.max(0, (rx*rx*ry*ry - rx*rx*py*py - ry*ry*px*px) / (rx*rx*py*py + ry*ry*px*px));
  sq = Math.sqrt(sq) * (largeArc===sweep ? -1 : 1);
  const cpx = sq*rx*py/ry, cpy = -sq*ry*px/rx;
  const cx0 = cos*cpx - sin*cpy + (x1+x2)/2;
  const cy0 = sin*cpx + cos*cpy + (y1+y2)/2;
  const a1 = Math.atan2((py-cpy)/ry, (px-cpx)/rx);
  let da = Math.atan2((-py-cpy)/ry, (-px-cpx)/rx) - a1;
  if (!sweep && da>0) da -= 2*Math.PI;
  if (sweep && da<0) da += 2*Math.PI;
  ctx.ellipse(cx0, cy0, rx, ry, xRot, a1, a1+da, !sweep);
}

function _drawSignGlyph(ctx, signIdx, cx, cy, size) {
  const paths = W_SIGN_PATHS[signIdx];
  const scale = size / 24;
  ctx.save();
  ctx.translate(cx - 12*scale, cy - 12*scale);
  ctx.beginPath();
  for (const d of paths) _tracePathCmds(ctx, _parseSvgPath(d), scale, scale);
  ctx.restore();
}

function _drawPlanetGlyph(ctx, key, cx, cy, size) {
  const glyph = PLANET_GLYPHS[key];
  if (!glyph) return;
  ctx.font = `${size}px serif`;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText(glyph, cx, cy);
}

function _buildSignOverlaySvg(W, ascLon) {
  const BASE = ascLon != null ? Math.floor(((ascLon % 360) + 360) % 360 / 30) * 30 : 0;
  const toA = lon => Math.PI - ((lon - BASE + 3600) % 360) * Math.PI / 180;
  const cx = W / 2, cy = W / 2;
  const M = W;

  const rSign = M * 0.305;
  const rBand = M * 0.378;
  const rArc  = rSign + (rBand - rSign) * 0.52;

  const ascSignIdx = ascLon != null ? Math.floor(((ascLon % 360) + 360) % 360 / 30) : -1;
  const fontSize = M * 0.022;

  let defs = '', textEls = '';

  for (let i = 0; i < 12; i++) {
    // a1 > a2 always: higher ecliptic lon → smaller toA angle
    const a1 = toA(i * 30);
    const a2 = toA(i * 30 + 30);
    const midAng = toA(i * 30 + 15);
    const isTop = Math.sin(midAng) < 0;

    const x1 = cx + Math.cos(a1) * rArc;
    const y1 = cy + Math.sin(a1) * rArc;
    const x2 = cx + Math.cos(a2) * rArc;
    const y2 = cy + Math.sin(a2) * rArc;

    // Top half: CW from a2→a1 (sweep=1) gives L→R tangent at the top
    // Bottom half: CCW from a1→a2 (sweep=0) gives L→R tangent at the bottom
    const d = isTop
      ? `M ${x2.toFixed(2)},${y2.toFixed(2)} A ${rArc.toFixed(2)},${rArc.toFixed(2)} 0 0,1 ${x1.toFixed(2)},${y1.toFixed(2)}`
      : `M ${x1.toFixed(2)},${y1.toFixed(2)} A ${rArc.toFixed(2)},${rArc.toFixed(2)} 0 0,0 ${x2.toFixed(2)},${y2.toFixed(2)}`;

    const hi = (i === ascSignIdx);
    const [r, g, b] = W_ELEM_LIGHT[W_ELEMENTS[i]];
    const fill = hi ? `rgb(${r},${g},${b})` : `rgba(${r},${g},${b},0.78)`;
    const weight = hi ? 'bold' : 'normal';
    const dy = isTop ? '-2' : '6';

    defs += `<path id="sa${i}" d="${d}"/>`;
    textEls += `<text dy="${dy}"><textPath startOffset="50%" href="#sa${i}" `
      + `style="text-anchor:middle;font-size:${fontSize.toFixed(1)}px;letter-spacing:0.07em;`
      + `font-family:'Space Mono',monospace;fill:${fill};font-weight:${weight}">`
      + `${SIGN_NAMES[i].toUpperCase()}</textPath></text>`;
  }

  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${W} ${W}" `
    + `style="position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none">`
    + `<defs>${defs}</defs>${textEls}</svg>`;
}

let _lastWheelParams  = null;
let _wheelObserver    = null;
let _wheelTimer       = null;
let _gridTransitionCb = null;  // pending transitionend listener

function _paintWheel(container, ascLon, mcLon, planets, cusps, animate) {
  const dpr = window.devicePixelRatio || 1;
  const W   = container.offsetWidth;

  container.innerHTML = '';
  container.style.position = 'relative';
  container.style.transform = '';

  const canvas = document.createElement('canvas');
  canvas.width  = W * dpr;
  canvas.height = W * dpr;
  canvas.style.width  = '100%';
  canvas.style.height = 'auto';
  canvas.style.display = 'block';
  container.appendChild(canvas);

  const svgWrap = document.createElement('div');
  svgWrap.innerHTML = _buildSignOverlaySvg(W, ascLon);
  container.appendChild(svgWrap.firstChild);

  if (animate) {
    container.classList.remove('wheel-appear');
    void container.offsetWidth;
    container.classList.add('wheel-appear');
  }

  _drawWheelCanvas(canvas, ascLon, mcLon, planets, cusps, dpr);
}

function renderWheel(ascLon, mcLon, planets, cusps, animate = false) {
  clearTimeout(_wheelTimer);
  // Cancel any previously registered transitionend listener
  if (_gridTransitionCb) {
    document.getElementById('main-grid')?.removeEventListener('transitionend', _gridTransitionCb);
    _gridTransitionCb = null;
  }
  _lastWheelParams = { ascLon, mcLon, planets, cusps, animate };

  const container = document.getElementById('zodiac-wheel');
  const W = container.offsetWidth;

  if (W < 50) {
    // Grid is mid-transition — render exactly when the column animation ends
    const grid = document.getElementById('main-grid');
    _gridTransitionCb = (e) => {
      if (e.propertyName !== 'grid-template-columns') return;
      grid.removeEventListener('transitionend', _gridTransitionCb);
      _gridTransitionCb = null;
      const p = _lastWheelParams;
      if (p) renderWheel(p.ascLon, p.mcLon, p.planets, p.cusps, p.animate);
    };
    grid.addEventListener('transitionend', _gridTransitionCb);
    return;
  }

  _paintWheel(container, ascLon, mcLon, planets, cusps, animate);

  // Set up resize observer once, after first successful paint
  if (!_wheelObserver) {
    _wheelObserver = new ResizeObserver(() => {
      clearTimeout(_wheelTimer);
      _wheelTimer = setTimeout(() => {
        const p = _lastWheelParams;
        if (!p) return;
        const c = document.getElementById('zodiac-wheel');
        if (c.offsetWidth >= 50) _paintWheel(c, p.ascLon, p.mcLon, p.planets, p.cusps, false);
      }, 120);
    });
    _wheelObserver.observe(container);
  }
}

function _drawWheelCanvas(canvas, ascLon, mcLon, planets, cusps, dpr) {
  const ctx = canvas.getContext('2d');
  const S = canvas.width / dpr;
  ctx.scale(dpr, dpr);

  const cx = S/2, cy = S/2;
  const M = S;

  // Radii — bigger zodiac band; planets outside
  const rCore    = M * 0.080;
  const rSign    = M * 0.320;
  const rBand    = M * 0.400;
  const rTube    = M * 0.438;
  const rPlanet  = M * 0.462;
  const rLabel   = M * 0.488;

  const BASE = ascLon != null ? Math.floor(((ascLon % 360) + 360) % 360 / 30) * 30 : 0;
  const toA = lon => Math.PI - ((lon - BASE + 3600) % 360) * Math.PI / 180;

  // ── White background disc ──
  ctx.save();
  ctx.fillStyle = '#fafafa';
  ctx.beginPath();
  ctx.arc(cx, cy, rLabel * 1.025, 0, 2*Math.PI);
  ctx.fill();
  ctx.restore();

  // ── House ring (inner band, same segments as sign ring) ──
  const cuspLons = (cusps && cusps.length === 12) ? cusps : null;
  const rHouseOuter = rSign;
  const rHouseInner = rSign - (rBand - rSign) * 0.5;   // half the sign band width
  const rHouseLabel = (rHouseOuter + rHouseInner) / 2;
  const hFontSz = M * 0.016;

  if (cuspLons) {
    // Sector fills — uniform grey
    for (let i = 0; i < 12; i++) {
      const a1 = toA(cuspLons[i]);
      const a2 = toA(cuspLons[(i + 1) % 12]);
      ctx.save();
      ctx.beginPath();
      ctx.arc(cx, cy, rHouseOuter, a1, a2, true);
      ctx.arc(cx, cy, rHouseInner, a2, a1, false);
      ctx.closePath();
      ctx.fillStyle = 'rgba(17,17,17,0.05)';
      ctx.fill();
      ctx.restore();
    }

    // Ring borders
    ctx.save();
    ctx.strokeStyle = 'rgba(17,17,17,0.18)';
    ctx.lineWidth = 0.6;
    ctx.beginPath(); ctx.arc(cx, cy, rHouseInner, 0, 2 * Math.PI); ctx.stroke();
    // Spoke lines at each cusp
    for (let i = 0; i < 12; i++) {
      const a = toA(cuspLons[i]);
      ctx.beginPath();
      ctx.moveTo(cx + Math.cos(a) * rHouseInner, cy + Math.sin(a) * rHouseInner);
      ctx.lineTo(cx + Math.cos(a) * rHouseOuter, cy + Math.sin(a) * rHouseOuter);
      ctx.stroke();
    }
    ctx.restore();

    // House numbers
    ctx.save();
    ctx.font = `${hFontSz}px 'Space Mono', monospace`;
    ctx.fillStyle = 'rgba(17,17,17,0.55)';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    for (let i = 0; i < 12; i++) {
      const midLon = cuspLons[i] + 15;
      const midAng = toA(midLon);
      const lx = cx + Math.cos(midAng) * rHouseLabel;
      const ly = cy + Math.sin(midAng) * rHouseLabel;
      ctx.fillText(String(i + 1), lx, ly);
    }
    ctx.restore();
  }

  // ── Sign sector fills ──
  const ascSignIdx = ascLon != null ? Math.floor(((ascLon % 360) + 360) % 360 / 30) : -1;
  for (let i = 0; i < 12; i++) {
    const a1 = toA(i * 30);
    const a2 = toA(i * 30 + 30);
    const [r,g,b] = W_ELEM_LIGHT[W_ELEMENTS[i]];
    const hi = (i === ascSignIdx);
    ctx.save();
    ctx.beginPath();
    ctx.arc(cx, cy, rBand, a1, a2, true);
    ctx.arc(cx, cy, rSign, a2, a1, false);
    ctx.closePath();
    if (hi) {
      ctx.shadowColor = `rgba(${r},${g},${b},0.9)`;
      ctx.shadowBlur = M * 0.06;
    }
    ctx.fillStyle = hi ? `rgba(${r},${g},${b},0.48)` : `rgba(${r},${g},${b},0.09)`;
    ctx.fill();
    if (hi) {
      ctx.shadowBlur = 0;
      ctx.strokeStyle = `rgba(${r},${g},${b},0.85)`;
      ctx.lineWidth = 1.2;
      ctx.stroke();
    }
    ctx.restore();
  }

  // ── Ring borders ──
  ctx.save();
  ctx.strokeStyle = 'rgba(17,17,17,0.18)';
  ctx.lineWidth = 0.6;
  ctx.beginPath(); ctx.arc(cx, cy, rSign, 0, 2*Math.PI); ctx.stroke();
  ctx.beginPath(); ctx.arc(cx, cy, rBand, 0, 2*Math.PI); ctx.stroke();
  ctx.restore();

  // ── Tick marks (rBand → rTube) ──
  for (let deg = 0; deg < 360; deg++) {
    const ang = toA(deg);
    const isBdy = (deg % 30 === 0);
    const isMaj = (deg % 5  === 0);
    const base  = rBand + (isBdy ? 0 : (rTube - rBand) * 0.12);
    const len   = isBdy ? (rTube - rBand) * 0.82 : isMaj ? (rTube - rBand) * 0.48 : (rTube - rBand) * 0.26;
    ctx.save();
    ctx.strokeStyle = isBdy ? 'rgba(17,17,17,0.45)' : isMaj ? 'rgba(17,17,17,0.22)' : 'rgba(17,17,17,0.10)';
    ctx.lineWidth = isBdy ? 0.9 : 0.5;
    ctx.beginPath();
    ctx.moveTo(cx + Math.cos(ang)*base,       cy + Math.sin(ang)*base);
    ctx.lineTo(cx + Math.cos(ang)*(base+len), cy + Math.sin(ang)*(base+len));
    ctx.stroke();
    ctx.restore();
  }

  // ── Metallic tube ring (teal, decorative frame) ──
  const tubeW = (rTube - rBand) * 0.26;
  const tubeR = rBand + (rTube - rBand) * 0.76;
  const tG = ctx.createRadialGradient(cx,cy, tubeR-tubeW*0.55, cx,cy, tubeR+tubeW*0.55);
  tG.addColorStop(0,   '#1a3838');
  tG.addColorStop(0.3, '#2a5555');
  tG.addColorStop(0.5, '#c8ece8');
  tG.addColorStop(0.7, '#2a5555');
  tG.addColorStop(1,   '#1a3838');
  ctx.save();
  ctx.strokeStyle = tG;
  ctx.lineWidth = tubeW;
  ctx.beginPath(); ctx.arc(cx, cy, tubeR, 0, 2*Math.PI); ctx.stroke();
  ctx.restore();

  ctx.save();
  ctx.strokeStyle = 'rgba(17,17,17,0.22)';
  ctx.lineWidth = 0.6;
  ctx.beginPath(); ctx.arc(cx, cy, rTube, 0, 2*Math.PI); ctx.stroke();
  ctx.restore();

  // ── Planet tick lines (rTube → planet track) ──
  for (const pos of Object.values(planets)) {
    if (!pos?.longitude) continue;
    const ang = toA(pos.longitude);
    ctx.save();
    ctx.strokeStyle = 'rgba(200,50,40,0.7)';
    ctx.lineWidth = 1.8;
    ctx.lineCap = 'round';
    ctx.beginPath();
    ctx.moveTo(cx + Math.cos(ang)*(rBand - M*0.010), cy + Math.sin(ang)*(rBand - M*0.010));
    ctx.lineTo(cx + Math.cos(ang)*(rPlanet - M*0.018), cy + Math.sin(ang)*(rPlanet - M*0.018));
    ctx.stroke();
    ctx.restore();
  }

  // ── Planet glyphs: iterative push-apart in longitude space ──
  // Ticks (above) stay at actual positions; glyphs are spread so they never overlap,
  // with a thin connector line when a glyph is displaced from its tick.
  const glyphSize = M * 0.054;
  const minDegGap = (glyphSize / rPlanet) * (180 / Math.PI) * 1.18; // min glyph separation in °

  const PLANET_ORDER = ['sun','moon','mercury','venus','mars','jupiter','saturn','uranus','neptune','pluto'];
  const rawPl = [];
  for (const key of PLANET_ORDER) {
    const pos = planets[key];
    if (!pos?.longitude) continue;
    rawPl.push({ key, pos, lon: ((pos.longitude % 360) + 360) % 360 });
  }
  rawPl.sort((a, b) => a.lon - b.lon);

  const Np = rawPl.length;
  if (Np > 0) {
    // Rotate array so the largest angular gap becomes the boundary — eliminates wrap-around
    let maxGap = -1, cutIdx = 0;
    for (let i = 0; i < Np; i++) {
      const j = (i + 1) % Np;
      const gap = j > 0 ? rawPl[j].lon - rawPl[i].lon : rawPl[0].lon + 360 - rawPl[Np-1].lon;
      if (gap > maxGap) { maxGap = gap; cutIdx = j; }
    }
    const pl = [...rawPl.slice(cutIdx), ...rawPl.slice(0, cutIdx)];

    // Unwrap display longitudes to be strictly monotonically increasing
    pl.forEach(p => p.disp = p.lon);
    for (let i = 1; i < Np; i++) {
      if (pl[i].disp <= pl[i-1].disp) pl[i].disp += 360;
    }

    // Iterative simultaneous push-apart (all pushes applied at once per iteration)
    for (let iter = 0; iter < 80; iter++) {
      const pushes = new Float64Array(Np);
      let anyPush = false;
      for (let i = 0; i < Np - 1; i++) {
        const gap = pl[i+1].disp - pl[i].disp;
        if (gap < minDegGap) {
          const push = (minDegGap - gap) * 0.5;
          pushes[i] -= push;
          pushes[i+1] += push;
          anyPush = true;
        }
      }
      if (!anyPush) break;
      pl.forEach((p, i) => p.disp += pushes[i]);
    }

    // Draw connector lines for displaced planets (behind glyphs)
    ctx.save();
    ctx.strokeStyle = 'rgba(17,17,17,0.18)';
    ctx.lineWidth = 0.6;
    for (const p of pl) {
      const dispMod = ((p.disp % 360) + 360) % 360;
      const diff = Math.abs(dispMod - p.lon);
      if (Math.min(diff, 360 - diff) < 0.4) continue;
      const actAng  = toA(p.lon);
      const dispAng = toA(p.disp);
      ctx.beginPath();
      ctx.moveTo(cx + Math.cos(actAng)  * (rPlanet - M * 0.018),
                 cy + Math.sin(actAng)  * (rPlanet - M * 0.018));
      ctx.lineTo(cx + Math.cos(dispAng) * (rPlanet - glyphSize * 0.6),
                 cy + Math.sin(dispAng) * (rPlanet - glyphSize * 0.6));
      ctx.stroke();
    }
    ctx.restore();

    // Draw glyphs and degree labels at display positions
    for (const { key, pos, disp } of pl) {
      const dispAng = toA(disp);
      const gx = cx + Math.cos(dispAng) * rPlanet;
      const gy = cy + Math.sin(dispAng) * rPlanet;
      const [r, g, b] = W_PLANET_COLOR[key] || [80, 80, 80];
      ctx.save();
      ctx.fillStyle = `rgb(${r},${g},${b})`;
      _drawPlanetGlyph(ctx, key, gx, gy, glyphSize);
      ctx.restore();
      const degNum = pos.degree ?? Math.floor(pos.longitude % 30);
      const lx = cx + Math.cos(dispAng) * rLabel;
      const ly = cy + Math.sin(dispAng) * rLabel;
      ctx.save();
      ctx.font = `${M * 0.019}px 'Space Mono', monospace`;
      ctx.fillStyle = 'rgba(17,17,17,0.60)';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(`${degNum}°`, lx, ly);
      ctx.restore();
    }
  }

  // ── ASC glow + label ──
  if (ascLon !== null && typeof ascLon === 'number') {
    const ascAng = toA(ascLon);
    const glowX = cx + Math.cos(ascAng) * rSign;
    const glowY = cy + Math.sin(ascAng) * rSign;
    const glowR = M * 0.11;
    const glow = ctx.createRadialGradient(glowX, glowY, 0, glowX, glowY, glowR);
    glow.addColorStop(0,    'rgba(255,255,200,0.55)');
    glow.addColorStop(0.35, 'rgba(255,230,100,0.28)');
    glow.addColorStop(1,    'rgba(255,210,80,0)');
    ctx.save();
    ctx.beginPath();
    ctx.arc(glowX, glowY, glowR, 0, 2 * Math.PI);
    ctx.fillStyle = glow;
    ctx.fill();
    ctx.restore();

    const lx = cx + Math.cos(ascAng)*(rSign * 0.78);
    const ly = cy + Math.sin(ascAng)*(rSign * 0.78);
    ctx.save();
    ctx.font = `bold ${M*0.020}px 'Space Mono', monospace`;
    ctx.fillStyle = 'rgba(17,17,17,0.65)';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText('ASCENDANT', lx, ly);
    ctx.restore();
  }

  // ── MC / IC / DSC labels ──
  ctx.save();
  ctx.font = `bold ${M*0.020}px 'Space Mono', monospace`;
  ctx.fillStyle = 'rgba(17,17,17,0.45)';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  if (mcLon !== null && typeof mcLon === 'number') {
    const mcAng = toA(mcLon);
    ctx.fillText('MC', cx + Math.cos(mcAng)*(rSign - M*0.012), cy + Math.sin(mcAng)*(rSign - M*0.012));
    const icAng = toA(mcLon + 180);
    ctx.fillText('IC', cx + Math.cos(icAng)*(rSign - M*0.012), cy + Math.sin(icAng)*(rSign - M*0.012));
  }
  if (ascLon !== null && typeof ascLon === 'number') {
    const dscAng = toA(ascLon + 180);
    ctx.fillText('DSC', cx + Math.cos(dscAng)*(rSign - M*0.012), cy + Math.sin(dscAng)*(rSign - M*0.012));
  }
  ctx.restore();

  // ── Center disc + rising sign glyph ──
  ctx.save();
  ctx.fillStyle = '#fafafa';
  ctx.beginPath();
  ctx.arc(cx, cy, rCore, 0, 2*Math.PI);
  ctx.fill();
  ctx.restore();

  ctx.save();
  ctx.strokeStyle = 'rgba(17,17,17,0.25)';
  ctx.lineWidth = 0.7;
  ctx.beginPath();
  ctx.arc(cx, cy, rCore, 0, 2*Math.PI);
  ctx.stroke();
  ctx.restore();

  if (ascSignIdx >= 0) {
    const glyphSize = rCore * 1.05;
    const [r,g,b] = W_ELEM_LIGHT[W_ELEMENTS[ascSignIdx]];
    ctx.save();
    ctx.strokeStyle = `rgb(${r},${g},${b})`;
    ctx.lineWidth = 1.2;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    _drawSignGlyph(ctx, ascSignIdx, cx, cy, glyphSize * 2);
    ctx.stroke();
    ctx.restore();
  }
}

/* ── (legacy buildWheel retained for reference, unused) ── */
function buildWheel(ascLon, mcLon, planets) {
  const R_OUTER  = 148;
  const R_SIGN   = 118;  // inner boundary of sign ring; planet band sits 84–118
  const R_PLANET = 102;  // planet glyph track center
  const R_CORE   = 84;   // inner core circle
  const R_ASPECT = 68;   // aspect line endpoint radius

  // Aries at top (12 o'clock), clockwise in SVG (y-down)
  const eclToSVG = ecl => ((ecl - 90) % 360 + 360) % 360;

  const polarXY = (deg, r) => {
    const rad = deg * Math.PI / 180;
    return [r * Math.cos(rad), r * Math.sin(rad)];
  };

  const f = v => v.toFixed(3);

  const arcPath = (a1, a2, r1, r2) => {
    const a2n = a2 < a1 ? a2 + 360 : a2;
    const [x1o, y1o] = polarXY(a1,  r2);
    const [x2o, y2o] = polarXY(a2n, r2);
    const [x2i, y2i] = polarXY(a2n, r1);
    const [x1i, y1i] = polarXY(a1,  r1);
    const large = (a2n - a1) > 180 ? 1 : 0;
    return [
      `M ${f(x1o)} ${f(y1o)}`,
      `A ${r2} ${r2} 0 ${large} 1 ${f(x2o)} ${f(y2o)}`,
      `L ${f(x2i)} ${f(y2i)}`,
      `A ${r1} ${r1} 0 ${large} 0 ${f(x1i)} ${f(y1i)}`,
      'Z'
    ].join(' ');
  };

  const ascLonN    = ((ascLon % 360) + 360) % 360;
  const ascSignIdx = Math.floor(ascLonN / 30);

  // Kerykeion path symbols — fill inherited from <use>
  const defs = SIGN_IDS.map((id, i) =>
    `<symbol id="z-${id}" viewBox="0 0 32 32"><path d="${SIGN_PATHS[i]}"/></symbol>`
  ).join('');

  const parts = [];

  // Background
  parts.push(`<circle r="175" fill="#0c0b09"/>`);

  // Sign sectors + kerykeion glyphs
  const RING_SZ = 16;
  for (let i = 0; i < 12; i++) {
    const a1 = eclToSVG(i * 30);
    const a2 = eclToSVG((i + 1) * 30 === 360 ? 0 : (i + 1) * 30);
    const isAsc = (i === ascSignIdx);
    const fill  = isAsc ? 'rgba(201,169,110,0.13)' : '#131210';
    parts.push(`<path d="${arcPath(a1, a2, R_SIGN, R_OUTER)}" fill="${fill}" stroke="#272320" stroke-width="0.75"/>`);

    const midSVG = eclToSVG(i * 30 + 15);
    const [lx, ly] = polarXY(midSVG, (R_SIGN + R_OUTER) / 2);
    const glyphColor = isAsc ? '#c9a96e' : '#3d3830';
    parts.push(`<use href="#z-${SIGN_IDS[i]}" x="${f(lx - RING_SZ / 2)}" y="${f(ly - RING_SZ / 2)}" width="${RING_SZ}" height="${RING_SZ}" fill="${glyphColor}"/>`);
  }

  // Subtle radial dividers in the planet band
  for (let i = 0; i < 12; i++) {
    const ang = eclToSVG(i * 30);
    const [sx, sy] = polarXY(ang, R_CORE);
    const [ex, ey] = polarXY(ang, R_SIGN);
    parts.push(`<line x1="${f(sx)}" y1="${f(sy)}" x2="${f(ex)}" y2="${f(ey)}" stroke="#1e1b17" stroke-width="0.5"/>`);
  }

  // Ring borders
  parts.push(`<circle r="${R_OUTER}" fill="none" stroke="#272320" stroke-width="0.75"/>`);
  parts.push(`<circle r="${R_SIGN}"  fill="none" stroke="#272320" stroke-width="0.75"/>`);
  parts.push(`<circle r="${R_CORE}"  fill="#0c0b09" stroke="#272320" stroke-width="0.75"/>`);

  // Aspect lines (inside core)
  const ASPECTS = [
    { angle:   0, orb: 8, color: '#5a5040', opacity: 0.55 },
    { angle:  60, orb: 5, color: '#3a7060', opacity: 0.45 },
    { angle:  90, orb: 7, color: '#7a3838', opacity: 0.50 },
    { angle: 120, orb: 7, color: '#385878', opacity: 0.50 },
    { angle: 180, orb: 8, color: '#603878', opacity: 0.45 },
  ];

  const planetList = Object.entries(planets || {})
    .filter(([, p]) => p != null)
    .map(([key, p]) => ({ key, lon: ((p.longitude % 360) + 360) % 360 }));

  for (let i = 0; i < planetList.length; i++) {
    for (let j = i + 1; j < planetList.length; j++) {
      const diff = Math.abs(planetList[i].lon - planetList[j].lon);
      const dist = Math.min(diff, 360 - diff);
      for (const asp of ASPECTS) {
        if (Math.abs(dist - asp.angle) <= asp.orb) {
          const [x1, y1] = polarXY(eclToSVG(planetList[i].lon), R_ASPECT);
          const [x2, y2] = polarXY(eclToSVG(planetList[j].lon), R_ASPECT);
          parts.push(`<line x1="${f(x1)}" y1="${f(y1)}" x2="${f(x2)}" y2="${f(y2)}" stroke="${asp.color}" stroke-width="0.75" opacity="${asp.opacity}"/>`);
          break;
        }
      }
    }
  }

  // Planet glyphs with basic collision nudge
  const sorted = [...planetList].sort((a, b) => eclToSVG(a.lon) - eclToSVG(b.lon));
  const radii  = new Map();
  for (let i = 0; i < sorted.length; i++) {
    const prevAng = i > 0 ? eclToSVG(sorted[i - 1].lon) : null;
    const curAng  = eclToSVG(sorted[i].lon);
    const gap     = prevAng !== null ? Math.abs(curAng - prevAng) : 999;
    radii.set(sorted[i].key, gap < 10 ? R_PLANET + (i % 2 === 0 ? -8 : 8) : R_PLANET);
  }

  for (const { key, lon } of planetList) {
    const svgA = eclToSVG(lon);
    const [px, py] = polarXY(svgA, radii.get(key));
    const glyph = PLANET_GLYPHS[key] || '·';
    parts.push(`<text x="${f(px)}" y="${f(py)}" text-anchor="middle" dominant-baseline="middle" font-size="10" fill="#b8a888" font-family="serif">${glyph}</text>`);
  }

  // MC marker
  const mcSVG = eclToSVG(((mcLon % 360) + 360) % 360);
  const [mx1, my1] = polarXY(mcSVG, R_CORE + 4);
  const [mx2, my2] = polarXY(mcSVG, R_OUTER + 4);
  const [mlx, mly] = polarXY(mcSVG, R_OUTER + 18);
  parts.push(`<line x1="${f(mx1)}" y1="${f(my1)}" x2="${f(mx2)}" y2="${f(my2)}" stroke="#4a4540" stroke-width="1"/>`);
  parts.push(`<text x="${f(mlx)}" y="${f(mly)}" text-anchor="middle" dominant-baseline="middle" font-size="7.5" fill="#4a4540" font-family="sans-serif" letter-spacing="1.5">MC</text>`);

  // ASC marker
  const ascSVG = eclToSVG(ascLonN);
  const [ax1, ay1] = polarXY(ascSVG, 18);
  const [ax2, ay2] = polarXY(ascSVG, R_OUTER + 4);
  const [adx, ady] = polarXY(ascSVG, (R_SIGN + R_OUTER) / 2);
  const [alx, aly] = polarXY(ascSVG, R_OUTER + 18);
  parts.push(`<line x1="${f(ax1)}" y1="${f(ay1)}" x2="${f(ax2)}" y2="${f(ay2)}" stroke="#c9a96e" stroke-width="1.5"/>`);
  parts.push(`<circle cx="${f(adx)}" cy="${f(ady)}" r="4.5" fill="#c9a96e"/>`);
  parts.push(`<text x="${f(alx)}" y="${f(aly)}" text-anchor="middle" dominant-baseline="middle" font-size="7.5" fill="#c9a96e" font-family="sans-serif" letter-spacing="1.5">ASC</text>`);

  // Core: rising sign path glyph + name
  const CORE_SZ = 36;
  parts.push(`<use href="#z-${SIGN_IDS[ascSignIdx]}" x="${f(-CORE_SZ / 2)}" y="${f(-CORE_SZ / 2 - 8)}" width="${CORE_SZ}" height="${CORE_SZ}" fill="#c9a96e"/>`);
  parts.push(`<text x="0" y="25" text-anchor="middle" dominant-baseline="middle" font-size="7.5" fill="#6a6358" font-family="sans-serif" letter-spacing="2.5">${SIGN_NAMES[ascSignIdx].toUpperCase()}</text>`);

  return `<svg viewBox="-190 -190 380 380" xmlns="http://www.w3.org/2000/svg" aria-hidden="true"><defs>${defs}</defs>${parts.join('')}</svg>`;
}

